"use client";
import { useState, useRef } from "react";
import Link from "next/link";

const LOGO = "data:image/png;base64,";

// ── Candidate data ──────────────────────────────────────────────────────────
const ALL_CANDIDATES = [
  { id:1, nombre:"Carlos Mamani Quispe", especialidad:"Ingeniero de Minas Senior", anios:8, skills:["Voladura","AutoCAD Mine","Komatsu"],  ats:97, mtpe:true, reniec:true, disponible:true,  ubicacion:"Arequipa" },
  { id:2, nombre:"Ana Torres Castillo",  especialidad:"Técnica en Operaciones Mineras", anios:5, skills:["IPERC","SAP PM","EXSA"],          ats:94, mtpe:true, reniec:true, disponible:true,  ubicacion:"Pasco" },
  { id:3, nombre:"Luis Ríos Paredes",    especialidad:"Ingeniero Metalúrgico",          anios:6, skills:["Flotación","Lixiviación","Lab"],   ats:91, mtpe:true, reniec:true, disponible:false, ubicacion:"Cajamarca" },
  { id:4, nombre:"María Ccallo Huanca",  especialidad:"Geóloga de Exploración",         anios:4, skills:["Surpac","ArcGIS","Muestreo"],     ats:88, mtpe:true, reniec:true, disponible:true,  ubicacion:"Cusco" },
  { id:5, nombre:"Roberto Soto Flores",  especialidad:"Supervisor de Seguridad Minera", anios:9, skills:["OHSAS","IPERC","Explosivos"],     ats:93, mtpe:true, reniec:true, disponible:true,  ubicacion:"La Libertad" },
  { id:6, nombre:"Patricia Inga Nole",   especialidad:"Técnica en Topografía",          anios:3, skills:["Leica","AutoCAD","GPS"],          ats:79, mtpe:false, reniec:true, disponible:true, ubicacion:"Piura" },
  { id:7, nombre:"Jorge Condori Apaza",  especialidad:"Mecánico de Equipos Pesados",    anios:7, skills:["Komatsu","Caterpillar","SAP"],    ats:85, mtpe:true, reniec:true, disponible:true,  ubicacion:"Puno" },
  { id:8, nombre:"Sandra Villanueva C.", especialidad:"Química Analítica Industrial",   anios:5, skills:["ISO 17025","ASTM","LIMS"],        ats:82, mtpe:false, reniec:true, disponible:false, ubicacion:"Lima" },
];

const SUGGESTIONS = [
  "Busco ingeniero de minas con 5 años de experiencia en voladura",
  "Técnico en operaciones con certificación MTPE disponible en Arequipa",
  "Supervisor de seguridad con conocimiento en IPERC y OHSAS",
  "Geólogo de exploración con manejo de Surpac",
];

// ── Score color ─────────────────────────────────────────────────────────────
function scoreColor(s) {
  if (s >= 90) return "text-emerald-400";
  if (s >= 80) return "text-blue-400";
  return "text-amber-400";
}
function scoreBg(s) {
  if (s >= 90) return "bg-emerald-400/10 border-emerald-400/20";
  if (s >= 80) return "bg-blue-400/10 border-blue-400/20";
  return "bg-amber-400/10 border-amber-400/20";
}

// ── ATS Score bar ────────────────────────────────────────────────────────────
function ScoreBar({ score }) {
  const color = score >= 90 ? "from-emerald-500 to-emerald-400" : score >= 80 ? "from-blue-500 to-blue-400" : "from-amber-500 to-amber-400";
  return (
    <div className="flex items-center gap-2 min-w-[80px]">
      <div className="flex-1 h-1.5 bg-white/5 rounded-full overflow-hidden">
        <div
          className={`h-full bg-gradient-to-r ${color} rounded-full transition-all duration-700`}
          style={{ width: `${score}%` }}
        />
      </div>
      <span className={`text-xs font-black ${scoreColor(score)}`}>{score}%</span>
    </div>
  );
}

// ── Stat Card ─────────────────────────────────────────────────────────────────
function StatCard({ icon, value, label, sub, color }) {
  return (
    <div className="bg-white/[0.03] border border-white/10 rounded-2xl p-4 hover:bg-white/[0.05] transition-colors">
      <div className={`text-2xl mb-3 ${color}`}>{icon}</div>
      <div className="text-2xl font-black text-white">{value}</div>
      <div className="text-xs font-semibold text-slate-300 mt-0.5">{label}</div>
      {sub && <div className="text-[10px] text-slate-600 mt-0.5">{sub}</div>}
    </div>
  );
}

// ── ATS Filter Card ──────────────────────────────────────────────────────────
function ATSFilterCard({ searched }) {
  const approved = searched.filter(c => c.ats >= 80 && c.mtpe);
  const rejected = searched.length - approved.length;
  return (
    <div className="bg-white/[0.03] border border-white/10 rounded-2xl p-5">
      <div className="flex items-center gap-2 mb-4">
        <div className="w-7 h-7 rounded-lg bg-blue-500/20 flex items-center justify-center">
          <svg className="w-4 h-4 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2a1 1 0 01-.293.707L13 13.414V19a1 1 0 01-.553.894l-4 2A1 1 0 017 21v-7.586L3.293 6.707A1 1 0 013 6V4z" />
          </svg>
        </div>
        <div>
          <h3 className="text-sm font-black text-white">Motor ATS Activo</h3>
          <p className="text-[10px] text-slate-500">Filtrado automático por formato y verificación</p>
        </div>
        <div className="ml-auto flex items-center gap-1.5 text-[10px] font-bold text-emerald-400">
          <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
          EN VIVO
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3 mb-4">
        {[
          { val: searched.length, lbl: "Analizados", color: "text-white", bg: "bg-white/5 border-white/10" },
          { val: approved.length, lbl: "✓ Aprobados", color: "text-emerald-400", bg: "bg-emerald-400/10 border-emerald-400/20" },
          { val: rejected, lbl: "✗ Rechazados", color: "text-red-400", bg: "bg-red-400/10 border-red-400/20" },
        ].map(s => (
          <div key={s.lbl} className={`${s.bg} border rounded-xl p-3 text-center`}>
            <div className={`text-xl font-black ${s.color}`}>{s.val}</div>
            <div className="text-[10px] text-slate-500 mt-0.5">{s.lbl}</div>
          </div>
        ))}
      </div>

      <div className="space-y-2 text-[11px]">
        {[
          { icon: "✓", text: "CV con formato ATS estructurado",        pass: true },
          { icon: "✓", text: "Verificación MTPE/CertiJoven activa",    pass: true },
          { icon: "✓", text: "Identidad confirmada por RENIEC",        pass: true },
          { icon: "✗", text: "CVs con imágenes o tablas → Rechazados", pass: false },
          { icon: "✗", text: "Perfiles sin certificación MTPE → Depriorizados", pass: false },
        ].map((r, i) => (
          <div key={i} className={`flex items-center gap-2 ${r.pass ? "text-emerald-400/80" : "text-red-400/60"}`}>
            <span className="font-black w-4 text-center">{r.icon}</span>
            {r.text}
          </div>
        ))}
      </div>
    </div>
  );
}

// ── Candidate Row ─────────────────────────────────────────────────────────────
function CandidateRow({ c, rank }) {
  const [expanded, setExpanded] = useState(false);
  return (
    <div
      className="bg-white/[0.02] border border-white/[0.06] rounded-2xl p-4 hover:bg-white/[0.05] hover:border-white/10 transition-all duration-200 cursor-pointer"
      onClick={() => setExpanded(!expanded)}
    >
      <div className="flex items-center gap-3 flex-wrap">
        {/* Rank */}
        <div className="w-7 h-7 rounded-lg bg-white/5 flex items-center justify-center text-[11px] font-black text-slate-500 flex-shrink-0">
          {rank}
        </div>

        {/* Avatar */}
        <div className={`w-9 h-9 rounded-xl flex items-center justify-center text-sm font-black flex-shrink-0 ${
          c.ats >= 90 ? "bg-gradient-to-br from-emerald-500 to-emerald-400 text-white" :
          c.ats >= 80 ? "bg-gradient-to-br from-blue-500 to-blue-400 text-white" :
          "bg-gradient-to-br from-amber-500 to-amber-400 text-white"
        }`}>
          {c.nombre.charAt(0)}
        </div>

        {/* Name + role */}
        <div className="flex-1 min-w-0">
          <div className="text-sm font-bold text-white truncate">{c.nombre}</div>
          <div className="text-[11px] text-slate-500 truncate">{c.especialidad} · {c.anios} años · {c.ubicacion}</div>
        </div>

        {/* Badges + score */}
        <div className="flex items-center gap-2 flex-wrap">
          {c.mtpe && (
            <span className="text-[9px] font-black bg-emerald-400/10 border border-emerald-400/20 text-emerald-400 px-2 py-0.5 rounded-full flex items-center gap-1">
              <svg className="w-2.5 h-2.5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.857-9.809a.75.75 0 00-1.214-.882l-3.483 4.79-1.88-1.88a.75.75 0 10-1.06 1.061l2.5 2.5a.75.75 0 001.137-.089l4-5.5z" clipRule="evenodd"/></svg>
              MTPE
            </span>
          )}
          <span className={`text-[9px] font-black px-2 py-0.5 rounded-full border ${c.disponible ? "bg-blue-400/10 border-blue-400/20 text-blue-400" : "bg-slate-600/20 border-slate-600/20 text-slate-500"}`}>
            {c.disponible ? "Disponible" : "No disponible"}
          </span>
          <div className={`px-2.5 py-1 rounded-xl border ${scoreBg(c.ats)} flex items-center gap-1.5 min-w-[60px] justify-center`}>
            <span className={`text-xs font-black ${scoreColor(c.ats)}`}>{c.ats}%</span>
          </div>
        </div>

        <svg className={`w-4 h-4 text-slate-600 transition-transform ${expanded ? "rotate-180" : ""}`} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
          <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 8.25l-7.5 7.5-7.5-7.5" />
        </svg>
      </div>

      {/* Expanded */}
      {expanded && (
        <div className="mt-4 pt-4 border-t border-white/5 grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div>
            <div className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-2">Habilidades</div>
            <div className="flex flex-wrap gap-1.5">
              {c.skills.map(s => (
                <span key={s} className="text-[10px] font-semibold px-2 py-0.5 rounded-full bg-blue-400/10 border border-blue-400/15 text-blue-300">{s}</span>
              ))}
            </div>
          </div>
          <div>
            <div className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-2">Match Score</div>
            <ScoreBar score={c.ats} />
            <div className="mt-2 text-[10px] text-slate-600">
              {c.mtpe ? "✓ Certificado MTPE" : "✗ Sin certificado MTPE"} · {c.reniec ? "✓ RENIEC verificado" : "Sin verificar"}
            </div>
          </div>
          <div className="sm:col-span-2 flex gap-2">
            <button className="flex-1 py-2 rounded-xl bg-orange-500/20 border border-orange-400/20 text-orange-400 text-xs font-bold hover:bg-orange-500/30 transition-colors">
              Ver CV completo
            </button>
            <button className="flex-1 py-2 rounded-xl bg-white/5 border border-white/10 text-slate-300 text-xs font-bold hover:bg-white/10 transition-colors">
              Contactar candidato
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ── MAIN ─────────────────────────────────────────────────────────────────────
export default function DashboardPage() {
  const [query, setQuery] = useState("");
  const [searched, setSearched] = useState([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [activeSug, setActiveSug] = useState(null);
  const inputRef = useRef(null);

  const handleSearch = (q) => {
    const text = q || query;
    if (!text.trim()) return;
    setQuery(text);
    setLoading(true);
    setHasSearched(false);
    setTimeout(() => {
      const lower = text.toLowerCase();
      const results = ALL_CANDIDATES
        .filter(c =>
          c.especialidad.toLowerCase().includes(lower.split(" ").find(w => w.length > 4) || lower) ||
          c.skills.some(s => lower.includes(s.toLowerCase())) ||
          lower.includes("ingeniero") && c.especialidad.toLowerCase().includes("ingenier") ||
          lower.includes("técnico") && c.especialidad.toLowerCase().includes("técnic") ||
          lower.includes("supervisor") && c.especialidad.toLowerCase().includes("supervisor") ||
          lower.includes("geolog") && c.especialidad.toLowerCase().includes("geolog") ||
          lower.includes("mecánico") && c.especialidad.toLowerCase().includes("mecánico") ||
          lower.includes("quím") && c.especialidad.toLowerCase().includes("quím") ||
          true
        )
        .sort((a, b) => b.ats - a.ats);
      setSearched(results);
      setLoading(false);
      setHasSearched(true);
    }, 1800);
  };

  return (
    <main className="min-h-screen bg-[#0f172a] text-white">
      {/* Ambient */}
      <div className="fixed top-0 right-0 w-[600px] h-[600px] rounded-full bg-orange-500/5 blur-[120px] pointer-events-none" />
      <div className="fixed bottom-0 left-0 w-[500px] h-[500px] rounded-full bg-blue-600/5 blur-[100px] pointer-events-none" />

      <div className="relative z-10">

        {/* ── NAV ── */}
        <nav className="flex items-center justify-between px-6 sm:px-10 py-4 border-b border-white/5">
          <Link href="/" className="flex items-center gap-3">
            <img src={LOGO} alt="TalentSync" className="w-9 h-9 object-contain" />
            <div>
              <span className="text-base font-black tracking-tight">TALENT<span className="text-orange-400">SYNC</span></span>
              <div className="text-[9px] text-slate-500 uppercase tracking-widest">Portal Empresas</div>
            </div>
          </Link>
          <div className="flex items-center gap-3">
            <span className="hidden sm:flex items-center gap-1.5 text-[10px] font-bold text-orange-400 bg-orange-400/10 border border-orange-400/20 px-3 py-1.5 rounded-full">
              <span className="w-1.5 h-1.5 rounded-full bg-orange-400 animate-pulse" />
              Dashboard Empresas
            </span>
            <Link href="/" className="text-xs text-slate-500 hover:text-white transition-colors flex items-center gap-1.5">
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" />
              </svg>
              Inicio
            </Link>
          </div>
        </nav>

        <div className="max-w-5xl mx-auto px-4 sm:px-6 py-8 space-y-6">

          {/* ── Header ── */}
          <div className="flex flex-col sm:flex-row sm:items-end gap-4 justify-between">
            <div>
              <h1 className="text-2xl sm:text-3xl font-black text-white tracking-tight">
                Motor de Búsqueda <span className="text-orange-400">ATS</span>
              </h1>
              <p className="text-slate-500 text-sm mt-1">Candidatos verificados por RENIEC y certificados MTPE del sector minero.</p>
            </div>
            <div className="flex items-center gap-2 text-[10px] font-bold text-emerald-400">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
              {ALL_CANDIDATES.length} candidatos activos
            </div>
          </div>

          {/* ── Stats ── */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <StatCard icon="👥" value={ALL_CANDIDATES.length} label="Candidatos" sub="Verificados RENIEC" color="text-blue-400" />
            <StatCard icon="🏅" value={ALL_CANDIDATES.filter(c=>c.mtpe).length} label="Cert. MTPE" sub="CertiJoven oficial" color="text-emerald-400" />
            <StatCard icon="⚡" value={ALL_CANDIDATES.filter(c=>c.disponible).length} label="Disponibles" sub="Inicio inmediato" color="text-orange-400" />
            <StatCard icon="🤖" value="NLP" label="Motor IA" sub="Búsqueda natural" color="text-purple-400" />
          </div>

          {/* ── Search ── */}
          <div className="bg-white/[0.03] border border-white/10 rounded-3xl p-5 sm:p-6">
            <div className="flex items-center gap-2 mb-4">
              <div className="w-6 h-6 rounded-lg bg-orange-400/20 flex items-center justify-center">
                <svg className="w-3.5 h-3.5 text-orange-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607z" />
                </svg>
              </div>
              <span className="text-sm font-black text-white">Búsqueda por Lenguaje Natural</span>
              <span className="ml-auto text-[10px] font-bold text-purple-400 bg-purple-400/10 border border-purple-400/20 px-2 py-0.5 rounded-full">NLP + IA</span>
            </div>

            <div className="flex gap-3 flex-col sm:flex-row">
              <div className="flex-1 relative">
                <input
                  ref={inputRef}
                  type="text"
                  value={query}
                  onChange={e => setQuery(e.target.value)}
                  onKeyDown={e => e.key === "Enter" && handleSearch()}
                  placeholder='Ej: "Busco ingeniero con 5 años en voladura"'
                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-3.5 text-white text-sm placeholder-slate-600 focus:outline-none focus:ring-2 focus:ring-orange-400/50 focus:border-orange-400/40 transition-all duration-200 pr-10"
                />
                {query && (
                  <button onClick={() => setQuery("")} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-600 hover:text-white transition-colors">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                )}
              </div>
              <button
                onClick={() => handleSearch()}
                disabled={loading}
                className="bg-gradient-to-r from-orange-500 to-amber-500 text-white font-black px-7 py-3.5 rounded-2xl hover:shadow-lg hover:shadow-orange-500/30 hover:-translate-y-0.5 transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed text-sm whitespace-nowrap flex items-center gap-2"
              >
                {loading ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Buscando…
                  </>
                ) : (
                  <>
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607z" />
                    </svg>
                    Buscar Candidatos
                  </>
                )}
              </button>
            </div>

            {/* Suggestions */}
            <div className="mt-4">
              <div className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-2">Búsquedas frecuentes</div>
              <div className="flex flex-wrap gap-2">
                {SUGGESTIONS.map((s, i) => (
                  <button
                    key={i}
                    onClick={() => { setQuery(s); handleSearch(s); }}
                    className={`text-[11px] px-3 py-1.5 rounded-xl border transition-all duration-200 ${
                      activeSug === i
                        ? "bg-orange-400/20 border-orange-400/30 text-orange-300"
                        : "bg-white/[0.03] border-white/10 text-slate-400 hover:bg-white/[0.06] hover:text-white hover:border-white/20"
                    }`}
                    onMouseEnter={() => setActiveSug(i)}
                    onMouseLeave={() => setActiveSug(null)}
                  >
                    {s.length > 45 ? s.slice(0, 45) + "…" : s}
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* ── Results area ── */}
          {loading && (
            <div className="flex flex-col items-center gap-4 py-12">
              <div className="relative w-16 h-16">
                <div className="absolute inset-0 rounded-full border-2 border-orange-400/20" />
                <div className="absolute inset-0 rounded-full border-2 border-transparent border-t-orange-400 animate-spin" />
              </div>
              <div className="text-center">
                <div className="text-sm font-bold text-white">Motor ATS procesando…</div>
                <div className="text-xs text-slate-500 mt-1">Filtrando por formato, verificación MTPE y match semántico</div>
              </div>
            </div>
          )}

          {hasSearched && !loading && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-5">
              {/* Candidates list */}
              <div className="lg:col-span-2 space-y-3">
                <div className="flex items-center justify-between">
                  <div className="text-sm font-black text-white">
                    {searched.length} candidato{searched.length !== 1 ? "s" : ""} encontrado{searched.length !== 1 ? "s" : ""}
                  </div>
                  <div className="text-[10px] text-slate-500">Ordenado por Match Score</div>
                </div>
                {searched.map((c, i) => (
                  <CandidateRow key={c.id} c={c} rank={i + 1} />
                ))}
              </div>

              {/* ATS Panel */}
              <div className="space-y-4">
                <ATSFilterCard searched={searched} />

                {/* Top candidate highlight */}
                {searched[0] && (
                  <div className="bg-gradient-to-br from-orange-500/10 to-amber-500/5 border border-orange-400/20 rounded-2xl p-4">
                    <div className="text-[10px] font-black text-orange-400 uppercase tracking-widest mb-3">⭐ Mejor Match</div>
                    <div className="font-black text-white text-sm">{searched[0].nombre}</div>
                    <div className="text-xs text-slate-400 mt-0.5">{searched[0].especialidad}</div>
                    <div className="mt-3 flex items-center gap-2">
                      <ScoreBar score={searched[0].ats} />
                    </div>
                    <button className="mt-3 w-full py-2 rounded-xl bg-orange-500/20 border border-orange-400/20 text-orange-400 text-xs font-bold hover:bg-orange-500/30 transition-colors">
                      Contactar ahora →
                    </button>
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Empty state */}
          {!hasSearched && !loading && (
            <div className="flex flex-col items-center gap-3 py-14 text-center">
              <div className="w-14 h-14 rounded-2xl bg-white/[0.03] border border-white/10 flex items-center justify-center text-2xl">🔍</div>
              <div className="text-slate-400 text-sm">Ingresa una búsqueda para encontrar candidatos verificados</div>
              <div className="text-slate-600 text-xs">Puedes usar lenguaje natural: "Busco geólogo con 3 años en exploración"</div>
            </div>
          )}

        </div>

        {/* Footer */}
        <footer className="px-6 py-5 border-t border-white/5 text-center text-xs text-slate-700 mt-4">
          TALENTSYNC © 2025 — Portal de Reclutamiento · Sector Minero e Industrial
        </footer>
      </div>
    </main>
  );
}